import 'package:http/http.dart' as http;
import 'dart:convert';

class ApiService {
  final String cloudApiUrl = 'https://api.example.com';
  final String localIoTDeviceUrl = 'http://192.168.x.x';

  Future<Map<String, dynamic>> fetchDataFromCloud() async {
    try {
      final response = await http.get(Uri.parse(cloudApiUrl));
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else {
        throw Exception('Failed to load data from cloud: ${response.statusCode}');
      }
    } catch (e) {
      throw Exception('Error fetching data from cloud: $e');
    }
  }

  Future<Map<String, dynamic>> fetchDataFromLocalIoTDevice() async {
    try {
      final response = await http.get(Uri.parse(localIoTDeviceUrl));
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else {
        throw Exception('Failed to load data from local IoT device: ${response.statusCode}');
      }
    } catch (e) {
      throw Exception('Error fetching data from local IoT device: $e');
    }
  }

  Future<void> sendDataToCloud(Map<String, dynamic> data) async {
    try {
      final response = await http.post(
        Uri.parse(cloudApiUrl),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode(data),
      );
      if (response.statusCode == 200) {
        print('Data sent to cloud successfully');
      } else {
        throw Exception('Failed to send data to cloud: ${response.statusCode}');
      }
    } catch (e) {
      throw Exception('Error sending data to cloud: $e');
    }
  }

  Future<void> sendDataToLocalIoTDevice(Map<String, dynamic> data) async {
    try {
      final response = await http.post(
        Uri.parse(localIoTDeviceUrl),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode(data),
      );
      if (response.statusCode == 200) {
        print('Data sent to local IoT device successfully');
      } else {
        throw Exception('Failed to send data to local IoT device: ${response.statusCode}');
      }
    } catch (e) {
      throw Exception('Error sending data to local IoT device: $e');
    }
  }
}